<!-- wp:code -->
<pre class="wp-block-code"><code lang="cpp" class="language-cpp">#include &lt;bits/stdc++.h&gt;

using namespace std;

struct node {
  int data;
  struct node * left, * right;
};

struct node *newNode(int data) {
  struct node *node = (struct node*) malloc(sizeof(struct node));
  node -&gt; data = data;
  node -&gt; left = NULL;
  node -&gt; right = NULL;

  return (node);
}

bool ans = false;

bool match(node * root, node *subRoot) {
  if (root &amp;&amp; subRoot) {
    bool a = match(root -&gt; left, subRoot -&gt; left);
    bool b = match(root -&gt; right, subRoot -&gt; right);

    if ((root -&gt; data == subRoot -&gt; data) &amp;&amp; a &amp;&amp; b)
      return true;
    else
      return false;
  } else if (!root &amp;&amp; !subRoot) return true;
  else return false;
}

void inorder(node * root, node * subRoot) {
  if (root) {
    inorder(root -&gt; left, subRoot);
    bool x = match(root, subRoot);
    if (x) ans = 1;
    inorder(root -&gt; right, subRoot);
  }
}

bool isSubtree(node * root, node * subRoot) {
  inorder(root, subRoot);
  return ans;
}

int main() {
  struct node *root = newNode(3);
  root-&gt;right = newNode(1);
  root-&gt;left = newNode(2);
  root-&gt;left-&gt;left = newNode(11);
  root-&gt;left-&gt;right = newNode(10);

  struct node *subRoot = newNode(2);
  subRoot-&gt;left = newNode(11);
  subRoot-&gt;right = newNode(10);

  cout &lt;&lt; boolalpha;
  isSubtree(root, subRoot);
  cout &lt;&lt; ans &lt;&lt; endl;
}
</code></pre>
<!-- /wp:code -->

<!-- wp:paragraph -->
<p><strong>Output:</strong> True</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Time Complexity:</strong> O(N*K), where k = no. of nodes in subtree and n = no. of nodes in the tree<br><br><strong>Space Complexity: </strong>O(1)</p>
